from flask import Flask, request, jsonify, session
from werkzeug.security import generate_password_hash, check_password_hash
import pyotp
import secrets
from functools import wraps
from datetime import datetime, timedelta

app = Flask(__name__)
app.secret_key = secrets.token_hex(32)
app.config['PERMANENT_SESSION_LIFETIME'] = timedelta(minutes=30)

# In-memory database (replace with actual database in production)
users_db = {}
sessions_db = {}
api_keys_db = {}

def require_auth(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        session_token = session.get('session_token')
        if not session_token or session_token not in sessions_db:
            return jsonify({'error': 'Unauthorized'}), 401
        
        session_data = sessions_db[session_token]
        if not session_data.get('authenticated'):
            return jsonify({'error': 'Unauthorized'}), 401
        
        if datetime.now() > session_data.get('expires_at'):
            del sessions_db[session_token]
            return jsonify({'error': 'Session expired'}), 401
        
        return f(*args, **kwargs)
    return decorated_function

def require_api_key(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        api_key = request.headers.get('X-API-Key')
        if not api_key or api_key not in api_keys_db:
            return jsonify({'error': 'Invalid API key'}), 401
        
        api_key_data = api_keys_db[api_key]
        if datetime.now() > api_key_data.get('expires_at'):
            return jsonify({'error': 'API key expired'}), 401
        
        request.username = api_key_data['username']
        return f(*args, **kwargs)
    return decorated_function

@app.route('/api/register', methods=['POST'])
def register():
    data = request.get_json()
    username = data.get('username')
    password = data.get('password')
    enable_mfa = data.get('enable_mfa', False)
    
    if not username or not password:
        return jsonify({'error': 'Username and password required'}), 400
    
    if username in users_db:
        return jsonify({'error': 'User already exists'}), 400
    
    mfa_secret = None
    if enable_mfa:
        mfa_secret = pyotp.random_base32()
    
    users_db[username] = {
        'password_hash': generate_password_hash(password),
        'mfa_enabled': enable_mfa,
        'mfa_secret': mfa_secret,
        'mfa_verified': False
    }
    
    response = {'message': 'User registered successfully'}
    if enable_mfa:
        totp = pyotp.TOTP(mfa_secret)
        provisioning_uri = totp.provisioning_uri(username, issuer_name="SecureApp")
        response['mfa_secret'] = mfa_secret
        response['provisioning_uri'] = provisioning_uri
    
    return jsonify(response), 201

@app.route('/api/login', methods=['POST'])
def login():
    data = request.get_json()
    username = data.get('username')
    password = data.get('password')
    
    if not username or not password:
        return jsonify({'error': 'Username and password required'}), 400
    
    user = users_db.get(username)
    if not user or not check_password_hash(user['password_hash'], password):
        return jsonify({'error': 'Invalid credentials'}), 401
    
    if user['mfa_enabled']:
        pending_token = secrets.token_urlsafe(32)
        sessions_db[pending_token] = {
            'username': username,
            'authenticated': False,
            'mfa_pending': True,
            'expires_at': datetime.now() + timedelta(minutes=5)
        }
        session['pending_token'] = pending_token
        return jsonify({
            'message': 'MFA required',
            'mfa_required': True,
            'pending_token': pending_token
        }), 200
    
    session_token = secrets.token_urlsafe(32)
    sessions_db[session_token] = {
        'username': username,
        'authenticated': True,
        'mfa_pending': False,
        'expires_at': datetime.now() + timedelta(minutes=30)
    }
    session['session_token'] = session_token
    
    return jsonify({
        'message': 'Login successful',
        'session_token': session_token
    }), 200

@app.route('/api/verify-mfa', methods=['POST'])
def verify_mfa():
    data = request.get_json()
    otp = data.get('otp')
    pending_token = session.get('pending_token') or data.get('pending_token')
    
    if not pending_token or pending_token not in sessions_db:
        return jsonify({'error': 'Invalid or expired session'}), 401
    
    session_data = sessions_db[pending_token]
    
    if not session_data.get('mfa_pending'):
        return jsonify({'error': 'MFA not required'}), 400
    
    if datetime.now() > session_data.get('expires_at'):
        del sessions_db[pending_token]
        return jsonify({'error': 'Session expired'}), 401
    
    username = session_data['username']
    user = users_db[username]
    
    if not user['mfa_enabled'] or not user['mfa_secret']:
        return jsonify({'error': 'MFA not enabled'}), 400
    
    totp = pyotp.TOTP(user['mfa_secret'])
    if not totp.verify(otp, valid_window=1):
        return jsonify({'error': 'Invalid OTP'}), 401
    
    del sessions_db[pending_token]
    if 'pending_token' in session:
        del session['pending_token']
    
    session_token = secrets.token_urlsafe(32)
    sessions_db[session_token] = {
        'username': username,
        'authenticated': True,
        'mfa_pending': False,
        'mfa_verified': True,
        'expires_at': datetime.now() + timedelta(minutes=30)
    }
    session['session_token'] = session_token
    
    return jsonify({
        'message': 'MFA verification successful',
        'session_token': session_token
    }), 200

