@app.route('/api/generate-api-key', methods=['POST'])
@require_auth
def generate_api_key():
    session_token = session.get('session_token')
    session_data = sessions_db[session_token]
    username = session_data['username']
    user = users_db[username]
    
    if user['mfa_enabled'] and not session_data.get('mfa_verified'):
        return jsonify({'error': 'MFA verification required to generate API keys'}), 403
    
    api_key = secrets.token_urlsafe(32)
    api_keys_db[api_key] = {
        'username': username,
        'created_at': datetime.now(),
        'expires_at': datetime.now() + timedelta(days=365)
    }
    
    return jsonify({
        'message': 'API key generated successfully',
        'api_key': api_key,
        'note': 'Store this key securely. It will not be shown again.'
    }), 201

